// --- Central error handler (must have 4 args) ---
app.use((err, _req, res, _next) => {
  // Log full error server-side; never leak stack to client
  console.error({ msg: 'unhandled_error', err: err.message, stack: err.stack });
  res.status(err.status ?? 500).json({ error: 'Internal server error' });
});

// --- Start server with error handling ---
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

server.on('error', (err) => {
  console.error({ msg: 'server_error', err: err.message });
  process.exit(1);
});

// --- Process-level safety nets ---
