const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { query, param, validationResult } = require('express-validator');
const pino = require('pino-http')();

const app = express();

// Security headers
app.use(helmet());

// Body parsing with explicit size limit (defense against large-payload DoS)
app.use(express.json({ limit: '10kb' }));

// Structured request logging
app.use(pino);

// Basic rate limit: 100 req / 15 min / IP
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// Validation helper
const handleValidation = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }
  next();
};

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get(
  '/users',
  [query('limit').optional().isInt({ min: 1, max: 100 }).toInt()],
  handleValidation,
  (req, res) => {
    // NOTE: strip PII unless caller is authenticated & authorized
    res.json([
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ]);
  }
);

app.get(
  '/users/:id',
  [param('id').isInt({ min: 1 }).toInt()],
  handleValidation,
  (req, res) => {
    // lookup by validated id
    res.json({ id: req.params.id, name: 'Alice' });
  }
);

// 404
app.use((req, res) => res.status(404).json({ error: 'Not found' }));

// Central error handler — must be 4 args
