const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { z } = require('zod');

// --- Config validation (fail fast at boot) ---
const EnvSchema = z.object({
  PORT: z.coerce.number().int().positive().default(3000),
  NODE_ENV: z.enum(['development', 'test', 'production']).default('development'),
});
const env = EnvSchema.parse(process.env);

const app = express();

// --- Security & hardening middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' }));           // cap body size
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // basic DoS mitigation

// --- Async handler wrapper (forwards errors to error middleware) ---
const asyncHandler = (fn) => (req, res, next) =>
  Promise.resolve(fn(req, res, next)).catch(next);

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Example validated route
const ListUsersQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(10),
});

app.get(
  '/users',
  asyncHandler(async (req, res) => {
    const { limit } = ListUsersQuery.parse(req.query); // throws on invalid
    const users = [
      { id: 1, name: 'Alice' }, // email removed unless caller is authorized
      { id: 2, name: 'Bob' },
    ].slice(0, limit);
    res.json(users);
