// --- Centralized error handler (must be last) ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  const isValidation = err?.name === 'ZodError';
  const status = isValidation ? 400 : err.status || 500;

  // Never leak stack traces to clients in production
  const body = {
    error: isValidation ? 'Invalid input' : 'Internal server error',
    ...(isValidation && { details: err.issues }),
  };

  // Structured server-side log (use pino/winston in real apps)
  console.error(JSON.stringify({
    level: 'error', status, msg: err.message, path: req.path,
  }));

  res.status(status).json(body);
});

// --- Process-level safety nets ---
process.on('unhandledRejection', (reason) => {
  console.error('unhandledRejection', reason);
});
process.on('uncaughtException', (err) => {
  console.error('uncaughtException', err);
  process.exit(1);
});

const server = app.listen(env.PORT, () => {
  console.log(`Server listening on :${env.PORT} (${env.NODE_ENV})`);
});

// Graceful shutdown for containers/orchestrators
for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => server.close(() => process.exit(0)));
}

module.exports = app;
```

