  const parsed = ListUsersQuery.safeParse(req.query);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid query' });
  // ...use parsed.data
});
```

## 5. Async handlers swallow rejections
Currently handlers are synchronous, but once you add DB/network calls, an unhandled `await` rejection will not reach the error handler in Express 4. Either upgrade to Express 5 or wrap async handlers:
```js
const asyncH = fn => (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next);
app.get('/users', asyncH(async (req, res) => { /* ... */ }));
```

