const asyncHandler = (fn) => (req, res, next) =>
  Promise.resolve(fn(req, res, next)).catch(next);

// Centralized error middleware (must have 4 args)
app.use((err, req, res, next) => {
  // Log full error server-side, never leak internals to the client
  console.error({ err, path: req.path, method: req.method });
  const status = err.status || 500;
  res.status(status).json({
    error: status >= 500 ? 'Internal Server Error' : err.message,
  });
});

// 404 fallback – do this AFTER routes, BEFORE error middleware
app.use((req, res) => res.status(404).json({ error: 'Not Found' }));

process.on('unhandledRejection', (err) => { console.error('unhandledRejection', err); });
process.on('uncaughtException',  (err) => { console.error('uncaughtException', err); process.exit(1); });
```

---

## 2. No input validation

**Problem:** `/users` currently takes no input, but once it does (query params, body, path params), the codebase has no validation layer. Ad-hoc `if (!req.body.x)` checks are error-prone.

**Fix:** Use a schema validator such as `zod`, `joi`, or `express-validator`, and reject anything that doesn't match. Example with `zod`:
```js
const { z } = require('zod');

const listUsersQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(20),
  cursor: z.string().regex(/^[A-Za-z0-9_-]{1,64}$/).optional(),
});

app.get('/users', asyncHandler(async (req, res) => {
  const { limit, cursor } = listUsersQuery.parse(req.query); // throws 400-able error
  // ...
}));
```
Key principles:
- **Allow-list, don't deny-list.** Validate shape, type, length, and character set.
- **Coerce once, at the edge.** Downstream code should never see raw `req.query`/`req.body`.
- **Reject unknown fields** (`.strict()` in zod) to prevent mass-assignment.

