const cors   = require('cors');            // explicit origin allow-list
const rateLimit = require('express-rate-limit');

app.disable('x-powered-by');               // don't advertise Express
app.use(helmet());
app.use(cors({ origin: ['https://your.app'], methods: ['GET'] }));
app.use(express.json({ limit: '100kb' })); // cap body size to prevent DoS
app.use(rateLimit({ windowMs: 60_000, max: 100 }));
```

