app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Centralized error handler (4 args signals Express it's an error handler)
app.use((err, req, res, next) => {
  console.error(err); // log full error server-side
  const status = err.status || 500;
  // Never leak err.message or err.stack in production
  res.status(status).json({ error: status === 500 ? 'Internal Server Error' : err.message });
});
```

**Handle process-level failures:**
```js
process.on('unhandledRejection', (reason) => { console.error('unhandledRejection', reason); });
process.on('uncaughtException', (err) => { console.error('uncaughtException', err); process.exit(1); });
```

## 2. No input validation

Neither route takes user input today, but as soon as `/users` accepts query params or a POST body, validation becomes critical. Establish the pattern now.

**Use a schema validator (e.g., `zod`, `joi`, or `express-validator`):**
```js
const { z } = require('zod');

const listUsersQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(20),
  offset: z.coerce.number().int().min(0).default(0),
});

app.get('/users', (req, res, next) => {
  const parsed = listUsersQuery.safeParse(req.query);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid query parameters', details: parsed.error.issues });
  }
  // use parsed.data — never req.query directly
  res.json(/* ... */);
});
```

Key principles:
- **Allowlist, don't blocklist.** Define exactly what you accept.
- **Coerce and bound.** Cap `limit` so an attacker can't request millions of rows.
- **Never trust `req.params`, `req.query`, `req.body`, or headers** without validation — treat all three as hostile.

## 3. Missing security middleware

Add these before any route handlers:

```js
