app.get('/users/:id', (req, res, next) => {
  const parsed = UserIdParam.safeParse(req.params);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid user id' });
  }
  // ... lookup logic; no PII in response unless caller is authenticated
  res.json({ id: parsed.data.id, name: 'Alice' });
});

app.get('/users', (req, res) => {
  // Omit email until auth is in place
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// --- 404 ---
app.use((req, res) => res.status(404).json({ error: 'Not found' }));

// --- Error handler (must be last, 4 args) ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  // Log internally; don't leak stack to client
  console.error({ msg: 'unhandled_error', err: err.message, stack: err.stack });
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

// --- Startup & graceful shutdown ---
if (require.main === module) {
  const port = Number(process.env.PORT) || 3000;
  const server = app.listen(port, () => console.log(`Server on ${port}`));

  const shutdown = (sig) => {
    console.log(`${sig} received, shutting down`);
    server.close(() => process.exit(0));
    setTimeout(() => process.exit(1), 10_000).unref();
  };
  process.on('SIGTERM', () => shutdown('SIGTERM'));
  process.on('SIGINT', () => shutdown('SIGINT'));
}

module.exports = app;
