app.use(helmet());
app.use(express.json({ limit: '10kb' }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    res.json([
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ]);
  } catch (err) { next(err); }
});

app.use((req, res) => res.status(404).json({ error: 'Not found' }));
app.use((err, req, res, _next) => {
  console.error(err);
  res.status(500).json({ error: 'Internal server error' });
});

const PORT = Number(process.env.PORT) || 3000;
if (require.main === module) {
  const server = app.listen(PORT, () => console.log(`Server on ${PORT}`));
  ['SIGTERM', 'SIGINT'].forEach(s => process.on(s, () => server.close(() => process.exit(0))));
}

module.exports = app;
```

### Priority order
1. Central error handler + 404 handler (prevents stack-trace leaks)
2. Helmet + disable `x-powered-by` + rate limiting
3. Input validation library wired in before any new routes
4. Auth/authorization on `/users`
5. Env-driven port + graceful shutdown
6. Structured logging

